import{_ as a,y as m,a as e,o as r,ag as g,D as o,g as n,I as c}from"./chunks/framework.RVu0gECZ.js";const N=JSON.parse('{"title":"Nhóm khách hàng","description":"","frontmatter":{},"headers":[],"relativePath":"customer/customer-group.md","filePath":"customer/customer-group.md","lastUpdated":1775811641000}'),u={name:"customer/customer-group.md"};function s(i,h,p,l,k,b){const t=m("ImagePopup");return r(),e("div",null,[h[0]||(h[0]=g('<h1 id="nhom-khach-hang" tabindex="-1">Nhóm khách hàng <a class="header-anchor" href="#nhom-khach-hang" aria-label="Permalink to &quot;Nhóm khách hàng&quot;">​</a></h1><p>Nhóm khách hàng cho phép bạn sắp xếp khách hàng, giảm giá cho họ và hạn chế quyền truy cập vào các sản phẩm hoặc danh mục cụ thể.</p><p>Với Nhóm khách hàng, bạn có thể: thiết lập nhóm khách hàng thân thiết — cấp quyền truy cập vào các sản phẩm hoặc danh mục cụ thể với mức giá chiết khấu cho một số khách hàng được chọn.</p><p>Các nhóm khách hàng xác định những khoản giảm giá nào có sẵn và loại thuế được liên kết với nhóm. Các nhóm khách hàng mặc định là Chung, Khách và Bán buôn.</p><h3 id="nhom-ban-buon" tabindex="-1">Nhóm bán buôn <a class="header-anchor" href="#nhom-ban-buon" aria-label="Permalink to &quot;Nhóm bán buôn&quot;">​</a></h3><p>Khách hàng bán buôn thường có quyền truy cập vào các sản phẩm hoặc gói sản phẩm không dành cho khách hàng bán lẻ và họ thường được giảm giá cho các sản phẩm họ mua. Cả hai điều này đều có thể được thiết lập bằng cách sử dụng tính năng Nhóm khách hàng.</p><p>Để hạn chế các sản phẩm bán buôn từ khách hàng bán lẻ, trước tiên bạn cần tạo danh mục cụ thể cho các sản phẩm đó.</p><p>Sau đó, bạn sẽ cần phân khúc khách hàng của mình để chỉ những khách hàng bán buôn mới có thể xem những sản phẩm đó.</p><h3 id="nhom-khach" tabindex="-1">Nhóm khách <a class="header-anchor" href="#nhom-khach" aria-label="Permalink to &quot;Nhóm khách&quot;">​</a></h3><p>Nhóm Khách là nhóm duy nhất có thể áp dụng cho khách và không thể chỉnh sửa hoặc xóa. Nhóm chưa đăng nhập cũng thuộc nhóm khách này.</p><h3 id="nhom-tong-hop" tabindex="-1">Nhóm tổng hợp <a class="header-anchor" href="#nhom-tong-hop" aria-label="Permalink to &quot;Nhóm tổng hợp&quot;">​</a></h3><p>Nhóm khách hàng chung đề cập đến những khách hàng không được xác định là Khách hàng Chuyên nghiệp và không muốn đặt mua sản phẩm với số lượng lớn.</p><hr><h3 id="đe-tao-nhom-khach-hang-moi-tai-vns-thuc-hien-theo-cac-buoc-sau" tabindex="-1">Để tạo nhóm khách hàng mới tại VNS thực hiện theo các bước sau: <a class="header-anchor" href="#đe-tao-nhom-khach-hang-moi-tai-vns-thuc-hien-theo-cac-buoc-sau" aria-label="Permalink to &quot;Để tạo nhóm khách hàng mới tại VNS thực hiện theo các bước sau:&quot;">​</a></h3><p><strong>Bước 1</strong>: Đăng nhập vào bảng quản trị của VNS và vào mục <strong>Khách hàng &gt;&gt; Nhóm</strong>. Theo mặc định, có ba nhóm khách hàng. Để tạo nhóm mới, hãy nhấp vào nút <strong>Tạo nhóm</strong> như hiển thị bên dưới.</p>',15)),o(t,{src:"/images/customer/createGroup.png",alt:"Create Group"}),h[1]||(h[1]=n("p",null,[n("strong",null,"Bước 2"),c(": Tiếp theo, bạn sẽ nhận được biểu mẫu để tạo nhóm mới. Điền vào nhóm "),n("strong",null,"Code"),c(" và "),n("strong",null,"Name"),c(" rồi nhấp vào nút "),n("strong",null,"Save Group"),c(" như trong hình bên dưới.")],-1)),o(t,{src:"/images/customer/newGroup.png",alt:"New Group"}),h[2]||(h[2]=n("p",null,[n("strong",null,"Bước 3"),c(": Bây giờ bạn sẽ thấy nhóm khách hàng mới đã đăng ký thành công.")],-1)),o(t,{src:"/images/customer/groupGrid.png",alt:"Group Grid"}),h[3]||(h[3]=n("p",null,"Như vậy với các bước trên bạn có thể dễ dàng tạo nhóm khách hàng mới từ bảng quản trị tại VNS.",-1)),h[4]||(h[4]=n("hr",null,null,-1))])}const v=a(u,[["render",s]]);export{N as __pageData,v as default};
